import{_ as e,o as s,c as t,a2 as n}from"./chunks/framework.BiT4WeDN.js";const u=JSON.parse('{"title":"Architecture","description":"How Yeast works under the hood","frontmatter":{"title":"Architecture","description":"How Yeast works under the hood"},"headers":[],"relativePath":"docs/architecture.md","filePath":"docs/architecture.md"}'),i={name:"docs/architecture.md"};function o(l,a,r,c,p,d){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><p>This page explains how Yeast works at a high level.</p><h2 id="mental-model" tabindex="-1">Mental Model <a class="header-anchor" href="#mental-model" aria-label="Permalink to &quot;Mental Model&quot;">​</a></h2><p>Yeast is a <strong>desired state</strong> system for local VMs. You declare what you want in <code>yeast.yaml</code>, and Yeast makes it happen.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>yeast.yaml (desired state)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>    Yeast</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>QEMU/KVM (actual state)</span></span></code></pre></div><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><h3 id="project-identity" tabindex="-1">Project Identity <a class="header-anchor" href="#project-identity" aria-label="Permalink to &quot;Project Identity&quot;">​</a></h3><p>Every Yeast project has a unique ID stored in <code>.yeast/project.json</code>.</p><h3 id="image-cache" tabindex="-1">Image Cache <a class="header-anchor" href="#image-cache" aria-label="Permalink to &quot;Image Cache&quot;">​</a></h3><p>Base images are cached at <code>~/.yeast/cache/images/</code>.</p><h3 id="instance-disks" tabindex="-1">Instance Disks <a class="header-anchor" href="#instance-disks" aria-label="Permalink to &quot;Instance Disks&quot;">​</a></h3><p>Each VM gets a copy-on-write (QCOW2) overlay disk.</p><h3 id="cloud-init" tabindex="-1">Cloud-Init <a class="header-anchor" href="#cloud-init" aria-label="Permalink to &quot;Cloud-Init&quot;">​</a></h3><p>Yeast uses cloud-init for first-boot provisioning.</p><h3 id="qemu-runtime" tabindex="-1">QEMU Runtime <a class="header-anchor" href="#qemu-runtime" aria-label="Permalink to &quot;QEMU Runtime&quot;">​</a></h3><p>Yeast starts QEMU with KVM acceleration and two network interfaces.</p><h3 id="state-management" tabindex="-1">State Management <a class="header-anchor" href="#state-management" aria-label="Permalink to &quot;State Management&quot;">​</a></h3><p>Yeast tracks runtime state in <code>state.json</code>.</p><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><h3 id="startup-flow" tabindex="-1">Startup Flow <a class="header-anchor" href="#startup-flow" aria-label="Permalink to &quot;Startup Flow&quot;">​</a></h3><ol><li>Load <code>.yeast/project.json</code></li><li>Load <code>yeast.yaml</code></li><li>Validate configuration</li><li>For each instance: <ul><li>Check/create disk.qcow2</li><li>Generate cloud-init files</li><li>Build seed.iso</li><li>Start QEMU</li><li>Wait for SSH</li><li>Run provisioning</li></ul></li></ol><h3 id="shutdown-flow" tabindex="-1">Shutdown Flow <a class="header-anchor" href="#shutdown-flow" aria-label="Permalink to &quot;Shutdown Flow&quot;">​</a></h3><ol><li>Load state.json</li><li>For each instance: <ul><li>Send ACPI shutdown</li><li>Wait for process to exit</li><li>Update state</li></ul></li></ol><h3 id="destroy-flow" tabindex="-1">Destroy Flow <a class="header-anchor" href="#destroy-flow" aria-label="Permalink to &quot;Destroy Flow&quot;">​</a></h3><ol><li>Stop all instances</li><li>For each instance: <ul><li>Remove disk.qcow2</li><li>Remove seed.iso</li><li>Remove state</li><li>Remove snapshots</li></ul></li></ol><h2 id="storage-layout" tabindex="-1">Storage Layout <a class="header-anchor" href="#storage-layout" aria-label="Permalink to &quot;Storage Layout&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.yeast/</span></span>
<span class="line"><span>  cache/</span></span>
<span class="line"><span>    images/</span></span>
<span class="line"><span>      ubuntu-24.04/</span></span>
<span class="line"><span>        disk.qcow2</span></span>
<span class="line"><span>  projects/</span></span>
<span class="line"><span>    &lt;project-id&gt;/</span></span>
<span class="line"><span>      .yeast/</span></span>
<span class="line"><span>        project.json</span></span>
<span class="line"><span>      yeast.yaml</span></span>
<span class="line"><span>      instances/</span></span>
<span class="line"><span>        &lt;name&gt;/</span></span>
<span class="line"><span>          disk.qcow2</span></span>
<span class="line"><span>          seed.iso</span></span>
<span class="line"><span>          state.json</span></span>
<span class="line"><span>          snapshots/</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./configuration.html">Configuration</a> - yeast.yaml reference</li><li><a href="./commands.html">Commands</a> - CLI command reference</li><li><a href="./troubleshooting.html">Troubleshooting</a> - Common issues and fixes</li></ul>`,29)])])}const m=e(i,[["render",o]]);export{u as __pageData,m as default};
